'use strict';
function validateHookConfig(config) {
  const errors = [];
  if (!config.name) errors.push('missing name');
  if (!config.event) errors.push('missing event');
  return { valid: errors.length === 0, errors };
}
module.exports = { validateHookConfig };

'use strict';
function createTracker() {
  const log = [];
  return {
    record(hookName, duration) { log.push({ hookName, duration, timestamp: Date.now() }); },
    getLog() { return [...log]; },
    average() { return log.length ? log.reduce((s, e) => s + e.duration, 0) / log.length : 0; }
  };
}
module.exports = { createTracker };

'use strict';
function resolveOrder(hooks) {
  const sorted = [...hooks].sort((a, b) => (a.priority || 5) - (b.priority || 5));
  return sorted.map(h => h.name);
}
module.exports = { resolveOrder };

'use strict';
function createErrorAggregator() {
  const errors = [];
  return {
    add(hookName, error) { errors.push({ hookName, message: error.message, timestamp: Date.now() }); },
    getByHook(name) { return errors.filter(e => e.hookName === name); },
    count() { return errors.length; }
  };
}
module.exports = { createErrorAggregator };

'use strict';
function createTimeoutManager(defaultMs) {
  const timeouts = {};
  return {
    set(hookName, ms) { timeouts[hookName] = ms || defaultMs; },
    get(hookName) { return timeouts[hookName] || defaultMs; },
    all() { return { ...timeouts }; }
  };
}
module.exports = { createTimeoutManager };

'use strict';
function createSideEffectLogger() {
  const effects = [];
  return {
    log(hookName, type, detail) { effects.push({ hookName, type, detail, timestamp: Date.now() }); },
    getEffects() { return [...effects]; },
    hasSideEffects(hookName) { return effects.some(e => e.hookName === hookName); }
  };
}
module.exports = { createSideEffectLogger };

'use strict';
function createMemoryMonitor() {
  const snapshots = [];
  return {
    snapshot(hookName) { snapshots.push({ hookName, rss: process.memoryUsage().rss, timestamp: Date.now() }); },
    getLeakCandidates(threshold) { return snapshots.filter(s => s.rss > (threshold || 50 * 1024 * 1024)); }
  };
}
module.exports = { createMemoryMonitor };

'use strict';
function scanHook(hookCode) {
  const issues = [];
  if (hookCode.includes('eval(')) issues.push('eval usage');
  if (hookCode.includes('child_process')) issues.push('child_process usage');
  return { safe: issues.length === 0, issues };
}
module.exports = { scanHook };

'use strict';
function checkVersion(hookName, minVersion, currentVersion) {
  return { hookName, compatible: currentVersion >= minVersion, current: currentVersion, minimum: minVersion };
}
module.exports = { checkVersion };

'use strict';
function createRecursionGuard(maxDepth) {
  const depth = { current: 0 };
  return {
    enter() { depth.current++; if (depth.current > (maxDepth || 10)) throw new Error('recursion limit'); },
    exit() { depth.current = Math.max(0, depth.current - 1); },
    depth() { return depth.current; }
  };
}
module.exports = { createRecursionGuard };
